            .@"real" => 152,
            .@"true" => 153,
            .@"false" => 154,
            .@"dot_lit" => 158,
            .@"dot_lbrace" => 160,
            .@"colon" => 66,
            .@"assign" => 68,
            .@"lparen" => 95,
            .@"comma" => 96,
            .@"rparen" => 99,
